gauss_wts = zeros(4, 1);
gauss_wts(1) = 1.000000000000000000e+00;
gauss_wts(2) = 1.000000000000000000e+00;
gauss_wts(3) = 1.000000000000000000e+00;
gauss_wts(4) = 1.000000000000000000e+00;

