			K(1, 1, :) = (J(1, 1, :) .* J(2, 2, :) - J(1, 2, :) .* J(2, 1, :)) .* (((J(1, 2, :) - J(2, 2, :)) .* (3 .^ (1 ./ 2) + 3) .^ 2 .* (D(1, 1) .* J(1, 2, :) - D(1, 1) .* J(2, 2, :) - D(6, 1) .* J(1, 1, :) + D(6, 1) .* J(2, 1, :))) ./ (144 .* detJ .^ 2) - ((J(1, 1, :) - J(2, 1, :)) .* (3 .^ (1 ./ 2) + 3) .^ 2 .* (D(1, 6) .* J(1, 2, :) - D(1, 6) .* J(2, 2, :) - D(6, 6) .* J(1, 1, :) + D(6, 6) .* J(2, 1, :))) ./ (144 .* detJ .^ 2));
