			K(1, 6, :) = (J(1, 1, :) .* J(2, 2, :) - J(1, 2, :) .* J(2, 1, :)) .* (((3 .^ (1 ./ 2) + 3) .* (D(1, 4) .* J(1, 2, :) - D(1, 4) .* J(2, 2, :) - D(6, 4) .* J(1, 1, :) + D(6, 4) .* J(2, 1, :)) .* (3 .* J(1, 1, :) + 3 .* J(2, 1, :) + 3 .^ (1 ./ 2) .* J(1, 1, :) - 3 .^ (1 ./ 2) .* J(2, 1, :))) ./ (144 .* detJ .^ 2) - ((3 .^ (1 ./ 2) + 3) .* (D(1, 5) .* J(1, 2, :) - D(1, 5) .* J(2, 2, :) - D(6, 5) .* J(1, 1, :) + D(6, 5) .* J(2, 1, :)) .* (3 .* J(1, 2, :) + 3 .* J(2, 2, :) + 3 .^ (1 ./ 2) .* J(1, 2, :) - 3 .^ (1 ./ 2) .* J(2, 2, :))) ./ (144 .* detJ .^ 2));
