			K(11, 5, :) = K(5, 11, :);
			K(11, 6, :) = K(6, 11, :);
			K(11, 7, :) = K(7, 11, :);
			K(11, 8, :) = K(8, 11, :);
			K(11, 9, :) = K(9, 11, :);
			K(11, 10, :) = K(10, 11, :);
			K(11, 11, :) = (J(1, 1, :) .* J(2, 2, :) - J(1, 2, :) .* J(2, 1, :)) .* (((3 .^ (1 ./ 2) + 3) .^ 2 .* (J(1, 1, :) + J(2, 1, :)) .* (D(2, 2) .* J(1, 1, :) + D(2, 2) .* J(2, 1, :) - D(6, 2) .* J(1, 2, :) - D(6, 2) .* J(2, 2, :))) ./ (144 .* detJ .^ 2) - ((3 .^ (1 ./ 2) + 3) .^ 2 .* (J(1, 2, :) + J(2, 2, :)) .* (D(2, 6) .* J(1, 1, :) + D(2, 6) .* J(2, 1, :) - D(6, 6) .* J(1, 2, :) - D(6, 6) .* J(2, 2, :))) ./ (144 .* detJ .^ 2));
			K(11, 12, :) = (J(1, 1, :) .* J(2, 2, :) - J(1, 2, :) .* J(2, 1, :)) .* (((3 .^ (1 ./ 2) + 3) .^ 2 .* (J(1, 1, :) + J(2, 1, :)) .* (D(2, 4) .* J(1, 1, :) + D(2, 4) .* J(2, 1, :) - D(6, 4) .* J(1, 2, :) - D(6, 4) .* J(2, 2, :))) ./ (144 .* detJ .^ 2) - ((3 .^ (1 ./ 2) + 3) .^ 2 .* (J(1, 2, :) + J(2, 2, :)) .* (D(2, 5) .* J(1, 1, :) + D(2, 5) .* J(2, 1, :) - D(6, 5) .* J(1, 2, :) - D(6, 5) .* J(2, 2, :))) ./ (144 .* detJ .^ 2));
			K(12, 1, :) = K(1, 12, :);
			K(12, 2, :) = K(2, 12, :);
			K(12, 3, :) = K(3, 12, :);
			K(12, 4, :) = K(4, 12, :);
			K(12, 5, :) = K(5, 12, :);
			K(12, 6, :) = K(6, 12, :);
			K(12, 7, :) = K(7, 12, :);
			K(12, 8, :) = K(8, 12, :);
			K(12, 9, :) = K(9, 12, :);
			K(12, 10, :) = K(10, 12, :);
			K(12, 11, :) = K(11, 12, :);
			K(12, 12, :) = (J(1, 1, :) .* J(2, 2, :) - J(1, 2, :) .* J(2, 1, :)) .* (((3 .^ (1 ./ 2) + 3) .^ 2 .* (J(1, 1, :) + J(2, 1, :)) .* (D(4, 4) .* J(1, 1, :) + D(4, 4) .* J(2, 1, :) - D(5, 4) .* J(1, 2, :) - D(5, 4) .* J(2, 2, :))) ./ (144 .* detJ .^ 2) - ((3 .^ (1 ./ 2) + 3) .^ 2 .* (J(1, 2, :) + J(2, 2, :)) .* (D(4, 5) .* J(1, 1, :) + D(4, 5) .* J(2, 1, :) - D(5, 5) .* J(1, 2, :) - D(5, 5) .* J(2, 2, :))) ./ (144 .* detJ .^ 2));

			%Terms of N matrix
			N(1, 1, :) = 1 ./ 6;
			N(1, 4, :) = 1 ./ 3 - 3 .^ (1 ./ 2) ./ 6;
			N(1, 7, :) = 1 ./ 6;
			N(1, 10, :) = 3 .^ (1 ./ 2) ./ 6 + 1 ./ 3;
			N(2, 2, :) = 1 ./ 6;
			N(2, 5, :) = 1 ./ 3 - 3 .^ (1 ./ 2) ./ 6;
			N(2, 8, :) = 1 ./ 6;
			N(2, 11, :) = 3 .^ (1 ./ 2) ./ 6 + 1 ./ 3;
			N(3, 3, :) = 1 ./ 6;
			N(3, 6, :) = 1 ./ 3 - 3 .^ (1 ./ 2) ./ 6;
			N(3, 9, :) = 1 ./ 6;
			N(3, 12, :) = 3 .^ (1 ./ 2) ./ 6 + 1 ./ 3;

	end

	%Accumulate K over Gauss points
	el_K = el_K + K * gauss_wts(g);

	%Evaluate rho * N'N|J|
	el_M_tmp = el_M_tmp + rho * pagemtimes(pagemtimes(N, 'transpose', N, 'none'), detJ) * gauss_wts(g);

end

%Diagonalise M
el_M = zeros(12, 12, no_els);
for i = 1:12
	el_M(i, i, :) = sum(el_M_tmp(:, i, :), 1);
end

%Remove unwanted DOFs from element matrices
j = ismember(loc_df, dofs_to_use);
el_K = el_K(j, j, :);
el_M = el_M(j, j, :);
el_C = el_C(j, j, :);
loc_nd = loc_nd(j);
loc_df = loc_df(j);

%Change dimension order of element matrices
el_K = permute(el_K, [3, 1, 2]);
el_M = permute(el_M, [3, 1, 2]);
el_C = permute(el_C, [3, 1, 2]);

end
